before_code:
module counter_32bit(
  input clk,
  input rst_n,
  output reg [31:0] count
);

  always @(posedge clk)
  begin
    if (!rst_n)
      count <= 32'b0;
    else
      count <= count + 1'b1;
  end

endmodule

after_code:
module counter_32bit(
  input clk,
  input rst_n,
  output reg [31:0] count
);

  always @(posedge clk or negedge rst_n)
  begin
    if (!rst_n)
      count <= 32'b0;
    else
      count <= count + 1'b1;
  end

endmodule
